import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../../services/auth';
import { updateInstructorProfile } from '../../services/instructors';

const Register = () => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    email: '', password: '', password2: '', first_name: '', last_name: '', is_instructor: false,
  });
  const [instructorData, setInstructorData] = useState({
    title: 'dr', bio: '', department: '', university: '', avatar: null, cv_file: null
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);

  const handleChange = (e) => {
    const value = e.target.type === 'checkbox' ? e.target.checked : e.target.value;
    setFormData({ ...formData, [e.target.name]: value });
  };
  const handleInstChange = (e) => {
    const value = e.target.files ? e.target.files[0] : e.target.value;
    setInstructorData({ ...instructorData, [e.target.name]: value });
  };

  const handleNext = (e) => {
    e.preventDefault(); setError('');
    if (!formData.email || !formData.first_name) { setError('يرجى تعبئة جميع الحقول المطلوبة'); return; }
    setStep(2);
  };

  const handleSubmitStep2 = async (e) => {
    e.preventDefault(); setError('');
    if (formData.password !== formData.password2) { setError('كلمتا المرور غير متطابقتين'); return; }
    if (formData.password.length < 8) { setError('كلمة المرور يجب أن تكون 8 أحرف على الأقل'); return; }
    
    setLoading(true);
    try {
      const res = await authService.register(formData);
      if (formData.is_instructor) {
        setStep(3); // انتقل لخطوة إكمال بيانات الدكتور
      } else {
        navigate('/dashboard/student');
      }
    } catch (err) {
      const d = err.response?.data;
      setError(typeof d === 'object' ? Object.values(d).flat().join(', ') : 'فشل التسجيل');
    } finally { setLoading(false); }
  };

  const handleSubmitInstructor = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      const user = authService.getUserFromStorage();
      const fd = new FormData();
      if (instructorData.avatar) fd.append('avatar', instructorData.avatar);
      if (instructorData.cv_file) fd.append('cv_file', instructorData.cv_file);
      fd.append('title', instructorData.title);
      fd.append('bio', instructorData.bio);
      fd.append('department', instructorData.department);
      fd.append('university', instructorData.university);

      await updateInstructorProfile(user.id, fd);
      navigate('/dashboard/instructor');
    } catch (err) {
      const d = err.response?.data;
      setError(typeof d === 'object' ? Object.values(d).flat().join(', ') : 'فشل رفع البيانات');
    } finally { setLoading(false); }
  };

  return (
    <div style={s.page}>
      <div style={s.left}>
        <div style={s.leftInner}>
          <div style={s.brand}>🎓 EduPlatform</div>
          <h1 style={s.leftTitle}>ابدأ رحلتك التعليمية</h1>
          <p style={s.leftSub}>سواء كنت طالباً أو مدرّساً، مكانك هنا</p>
          <div style={s.steps}>
            <div style={s.stepItem(step >= 1)}><div style={s.stepCircle(step >= 1)}>1</div><span style={s.stepLabel(step >= 1)}>بياناتك</span></div>
            <div style={s.stepLine(step >= 2)} />
            <div style={s.stepItem(step >= 2)}><div style={s.stepCircle(step >= 2)}>2</div><span style={s.stepLabel(step >= 2)}>الحساب</span></div>
            {formData.is_instructor && (
              <>
                <div style={s.stepLine(step >= 3)} />
                <div style={s.stepItem(step >= 3)}><div style={s.stepCircle(step >= 3)}>3</div><span style={s.stepLabel(step >= 3)}>بيانات الدكتور</span></div>
              </>
            )}
          </div>
        </div>
      </div>

      <div style={s.right}>
        <div style={s.formBox}>
          <h2 style={s.formTitle}>{step === 1 ? 'إنشاء حساب 🚀' : step === 2 ? 'كلمة المرور 🔑' : 'إكمال بيانات الدكتور 🎓'}</h2>
          
          {step === 1 && (
            <form onSubmit={handleNext} style={s.form}>
              <div style={s.row2}>
                <div style={s.field}><label style={s.label}>الاسم الأول *</label>
                  <input style={s.input} name="first_name" value={formData.first_name} onChange={handleChange} placeholder="Ahmed" required /></div>
                <div style={s.field}><label style={s.label}>اسم العائلة</label>
                  <input style={s.input} name="last_name" value={formData.last_name} onChange={handleChange} placeholder="Mohamed" /></div>
              </div>
              <div style={s.field}><label style={s.label}>البريد الإلكتروني *</label>
                <input style={s.input} type="email" name="email" value={formData.email} onChange={handleChange} placeholder="email@example.com" required /></div>
              {error && <div style={s.errorBox}>⚠ {error}</div>}
              <button type="submit" style={s.submitBtn}>التالي →</button>
            </form>
          )}

          {step === 2 && (
            <form onSubmit={handleSubmitStep2} style={s.form}>
              <div style={s.field}><label style={s.label}>كلمة المرور *</label>
                <div style={s.inputWrap}><input style={s.input} type={showPass?'text':'password'} name="password" value={formData.password} onChange={handleChange} required />
                <button type="button" style={s.eyeBtn} onClick={()=>setShowPass(!showPass)}>{showPass?'🙈':'👁'}</button></div></div>
              <div style={s.field}><label style={s.label}>تأكيد كلمة المرور *</label>
                <input style={s.input} type="password" name="password2" value={formData.password2} onChange={handleChange} required /></div>
              <div style={s.typeWrap}><p style={s.typeTitle}>نوع الحساب</p>
                <div style={s.typeCards}>
                  <div style={s.typeCard(!formData.is_instructor)} onClick={()=>setFormData({...formData, is_instructor:false})}><span>📚</span><span style={s.typeCardLabel}>طالب</span></div>
                  <div style={s.typeCard(formData.is_instructor)} onClick={()=>setFormData({...formData, is_instructor:true})}><span>🎓</span><span style={s.typeCardLabel}>مدرّس</span></div>
                </div></div>
              <div style={{display:'flex', gap:10}}>
                <button type="button" style={s.backBtn} onClick={()=>{setStep(1);setError('');}}>← رجوع</button>
                <button type="submit" style={{...s.submitBtn, flex:1}} disabled={loading}>{loading?'⏳ جاري...':'إنشاء الحساب'}</button>
              </div>
            </form>
          )}

          {step === 3 && formData.is_instructor && (
            <form onSubmit={handleSubmitInstructor} style={s.form}>
              <div style={s.row2}>
                <div style={s.field}><label style={s.label}>اللقب *</label>
                  <select style={s.input} name="title" value={instructorData.title} onChange={handleInstChange}>
                    <option value="dr">دكتور</option><option value="prof">أستاذ دكتور</option><option value="eng">مهندس</option><option value="mr">أستاذ</option>
                  </select></div>
                <div style={s.field}><label style={s.label}>القسم</label>
                  <input style={s.input} name="department" value={instructorData.department} onChange={handleInstChange} placeholder="Computer Science" /></div>
              </div>
              <div style={s.field}><label style={s.label}>الجامعة</label>
                <input style={s.input} name="university" value={instructorData.university} onChange={handleInstChange} placeholder="Cairo University" /></div>
              <div style={s.field}><label style={s.label}>نبذة عنك</label>
                <textarea style={{...s.input, minHeight:80, resize:'vertical'}} name="bio" value={instructorData.bio} onChange={handleInstChange} placeholder="خبرتك الأكاديمية والبحثية..." /></div>
              <div style={s.row2}>
                <div style={s.field}><label style={s.label}>الصورة الشخصية</label>
                  <input type="file" style={s.input} accept="image/*" name="avatar" onChange={handleInstChange} /></div>
                <div style={s.field}><label style={s.label}>السيرة الذاتية (PDF)</label>
                  <input type="file" style={s.input} accept=".pdf" name="cv_file" onChange={handleInstChange} /></div>
              </div>
              {error && <div style={s.errorBox}>⚠ {error}</div>}
              <div style={{display:'flex', gap:10}}>
                <button type="button" style={s.backBtn} onClick={()=>setStep(2)}>← رجوع</button>
                <button type="submit" style={{...s.submitBtn, flex:1}} disabled={loading}>{loading?'⏳ جاري الحفظ...':'إكمال التسجيل 🎉'}</button>
              </div>
            </form>
          )}
          <p style={s.switchText}>عندك حساب بالفعل؟ <Link to="/login" style={s.switchLink}>سجّل دخولك</Link></p>
        </div>
      </div>
    </div>
  );
};

// ⬇️ نفس الـ Styles الموجودة في ملفك الأصلي (احتفظ بها كما هي)
